pub struct ConfigCreateChatInviteLink {
pub mut:
	chat_id              string // [JSON-serialized: int | string] Unique identifier for the target chat or username of the target channel in the format @username
	name                 string @[omitempty] // Invite link name; 0-32 characters
	expire_date          i64    @[omitempty] // Point in time (Unix timestamp) when the link will expire
	member_limit         i64    @[omitempty] // The maximum number of users that can be members of the chat simultaneously after joining the chat via this invite link; 1-99999
	creates_join_request bool   @[omitempty] // True, if users joining the chat via the link need to be approved by chat administrators. If True, member_limit can't be specified.
}

pub fn (b Bot) create_chat_invite_link(conf ConfigCreateChatInviteLink) !ChatInviteLink {
	resp := b.http_request('createChatInviteLink', json.encode(conf))!
	return json.decode(ChatInviteLink, resp)!
}

