	provider_data                 string @[omitempty] // JSON-serialized data about the invoice, which will be shared with the payment provider. A detailed description of required fields should be provided by the payment provider.
	photo_url                     string @[omitempty] // URL of the product photo for the invoice. Can be a photo of the goods or a marketing image for a service. People like it better when they see what they are paying for.
	photo_size                    i64    @[omitempty] // Photo size in bytes
	photo_width                   i64    @[omitempty] // Photo width
	photo_height                  i64    @[omitempty] // Photo height
	need_name                     bool   @[omitempty] // Pass True if you require the user's full name to complete the order. Ignored for payments in Telegram Stars.
	need_phone_number             bool   @[omitempty] // Pass True if you require the user's phone number to complete the order. Ignored for payments in Telegram Stars.
	need_email                    bool   @[omitempty] // Pass True if you require the user's email address to complete the order. Ignored for payments in Telegram Stars.
	need_shipping_address         bool   @[omitempty] // Pass True if you require the user's shipping address to complete the order. Ignored for payments in Telegram Stars.
	send_phone_number_to_provider bool   @[omitempty] // Pass True if the user's phone number should be sent to the provider. Ignored for payments in Telegram Stars.
	send_email_to_provider        bool   @[omitempty] // Pass True if the user's email address should be sent to the provider. Ignored for payments in Telegram Stars.
	is_flexible                   bool   @[omitempty] // Pass True if the final price depends on the shipping method. Ignored for payments in Telegram Stars.
	disable_notification          bool   @[omitempty] // Sends the message silently. Users will receive a notification with no sound.
	protect_content               bool   @[omitempty] // Protects the contents of the sent message from forwarding and saving
	allow_paid_broadcast          bool   @[omitempty] // Pass True to allow up to 1000 messages per second, ignoring broadcasting limits for a fee of 0.1 Telegram Stars per message. The relevant Stars will be withdrawn from the bot's balance.
	message_effect_id             string @[omitempty] // Unique identifier of the message effect to be added to the message; for private chats only
	suggested_post_parameters     string @[omitempty] // [JSON-serialized: SuggestedPostParameters] A JSON-serialized object containing the parameters of the suggested post to send; for direct messages chats only. If the message is sent as a reply to another suggested post, then that suggested post is automatically declined.
	reply_parameters              string @[omitempty] // [JSON-serialized: ReplyParameters] Description of the message to reply to
	reply_markup                  string @[omitempty] // [JSON-serialized: InlineKeyboardMarkup] A JSON-serialized object for an inline keyboard. If empty, one 'Pay total price' button will be shown. If not empty, the first button must be a Pay button.
}

