	resp := b.http_request('createInvoiceLink', json.encode(conf))!
	return resp.trim('"')
}

// answer_shipping_query If you sent an invoice requesting a shipping address and the parameter is_flexible was specified, the Bot API will send an Update with a shipping_query field to the bot. Use this method to reply to shipping queries. On success, True is returned.
@[params]
pub struct ConfigAnswerShippingQuery {
pub mut:
	shipping_query_id string // Unique identifier for the query to be answered
	ok                bool   // Pass True if delivery to the specified address is possible and False if there are any problems (for example, if delivery to the specified address is not possible)
	shipping_options  string @[omitempty] // [JSON-serialized: Array<ShippingOption>] Required if ok is True. A JSON-serialized array of available shipping options.
	error_message     string @[omitempty] // Required if ok is False. Error message in human readable form that explains why it is impossible to complete the order (e.g. “Sorry, delivery to your desired address is unavailable”). Telegram will display this message to the user.
}

pub fn (b Bot) answer_shipping_query(conf ConfigAnswerShippingQuery) !bool {
	resp := b.http_request('answerShippingQuery', json.encode(conf))!
	return resp == 'true'
}

// answer_pre_checkout_query Once the user has confirmed their payment and shipping details, the Bot API sends the final confirmation in the form of an Update with the field pre_checkout_query. Use this method to respond to such pre-checkout queries. On success, True is returned. Note: The Bot API must receive an answer within 10 seconds after the pre-checkout query was sent.
@[params]
pub struct ConfigAnswerPreCheckoutQuery {
pub mut:
	pre_checkout_query_id string // Unique identifier for the query to be answered
	ok                    bool   // Specify True if everything is alright (goods are available, etc.) and the bot is ready to proceed with the order. Use False if there are any problems.
	error_message         string @[omitempty] // Required if ok is False. Error message in human readable form that explains the reason for failure to proceed with the checkout (e.g. "Sorry, somebody just bought the last of our amazing black T-shirts while you were busy filling out your payment details. Please choose a different color or garment!"). Telegram will display this message to the user.
}

pub fn (b Bot) answer_pre_checkout_query(conf ConfigAnswerPreCheckoutQuery) !bool {
	resp := b.http_request('answerPreCheckoutQuery', json.encode(conf))!
	return resp == 'true'
}

