	resp := b.http_request('setPassportDataErrors', json.encode(conf))!
	return resp == 'true'
}

// send_game Use this method to send a game. On success, the sent Message is returned.
@[params]
pub struct ConfigSendGame {
pub mut:
	business_connection_id string @[omitempty] // Unique identifier of the business connection on behalf of which the message will be sent
	chat_id                string // [JSON-serialized: int | string] Unique identifier for the target chat or username of the target bot in the format @username. Games can't be sent to channel direct messages chats and channel chats.
	message_thread_id      i64 @[omitempty] // Unique identifier for the target message thread (topic) of a forum; for forum supergroups and private chats of bots with forum topic mode enabled only
	game_short_name        string // Short name of the game, serves as the unique identifier for the game. Set up your games via @BotFather.
	disable_notification   bool   @[omitempty] // Sends the message silently. Users will receive a notification with no sound.
	protect_content        bool   @[omitempty] // Protects the contents of the sent message from forwarding and saving
	allow_paid_broadcast   bool   @[omitempty] // Pass True to allow up to 1000 messages per second, ignoring broadcasting limits for a fee of 0.1 Telegram Stars per message. The relevant Stars will be withdrawn from the bot's balance.
	message_effect_id      string @[omitempty] // Unique identifier of the message effect to be added to the message; for private chats only
	reply_parameters       string @[omitempty] // [JSON-serialized: ReplyParameters] Description of the message to reply to
	reply_markup           string @[omitempty] // [JSON-serialized: InlineKeyboardMarkup] A JSON-serialized object for an inline keyboard. If empty, one 'Play game_title' button will be shown. If not empty, the first button must launch the game.
}

pub fn (b Bot) send_game(conf ConfigSendGame) !Message {
	resp := b.http_request('sendGame', json.encode(conf))!
	return json.decode(Message, resp)!
}

// set_game_score Use this method to set the score of the specified user in a game message. On success, if the message is not an inline message, the Message is returned, otherwise True is returned. Returns an error, if the new score is not greater than the user's current score in the chat and force is False.
@[params]
pub struct ConfigSetGameScore {
pub mut:
	user_id              i64 // User identifier
	score                i64 // New score, must be non-negative
	force                bool   @[omitempty] // Pass True if the high score is allowed to decrease. This can be useful when fixing mistakes or banning cheaters.
	disable_edit_message bool   @[omitempty] // Pass True if the game message should not be automatically edited to include the current scoreboard
	chat_id              i64    @[omitempty] // Required if inline_message_id is not specified. Unique identifier for the target chat.
	message_id           i64    @[omitempty] // Required if inline_message_id is not specified. Identifier of the sent message.
	inline_message_id    string @[omitempty] // Required if chat_id and message_id are not specified. Identifier of the inline message.
}

// Returns one of: Message, bool (decoded here as Message).
pub fn (b Bot) set_game_score(conf ConfigSetGameScore) !Message {
	resp := b.http_request('setGameScore', json.encode(conf))!
	return json.decode(Message, resp)!
}

